// src/ai/aiService.js
// ✅ TEMP WORKING VERSION (no API needed)
// Simulates AI responses so your UI works perfectly

// Utility delay (simulate API)
function delay(ms) {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

// ──────────────────────────────────────────────
// 1. AI POST SUMMARY
// ──────────────────────────────────────────────
export async function generateSummary(title, content) {
  await delay(800);

  return `This article discusses ${title.toLowerCase()} in a clear and engaging way. 
It highlights key ideas and provides useful insights for readers. 
Overall, it offers a practical understanding of the topic.`;
}

// ──────────────────────────────────────────────
// 2. AI WRITING ASSISTANT
// ──────────────────────────────────────────────
export async function analyzeWriting(title, content) {
  await delay(1200);

  const lengthScore = Math.min(10, Math.floor(content.length / 80));

  return {
    score: lengthScore || 7,
    tone: "Professional",
    readability: content.length > 300 ? "Medium" : "Easy",
    strengths: [
      "Clear topic selection",
      "Good content structure",
      "Relevant and engaging subject"
    ],
    improvements: [
      "Add real-world examples",
      "Improve the introduction hook",
      "Break content into smaller paragraphs"
    ],
    rewrittenIntro: `In today's fast-changing world, ${title.toLowerCase()} is becoming increasingly important. This article explores its key ideas in a simple and practical way.`
  };
}

// ──────────────────────────────────────────────
// 3. AI TAG GENERATOR
// ──────────────────────────────────────────────
export async function generateTags(title, content) {
  await delay(700);

  const baseTags = ["blog", "tech", "writing", "ideas", "content"];

  if (title.toLowerCase().includes("react")) baseTags.push("react");
  if (title.toLowerCase().includes("ai")) baseTags.push("ai");

  return baseTags.slice(0, 5);
}

// ──────────────────────────────────────────────
// 4. COMMENT SENTIMENT
// ──────────────────────────────────────────────
export async function analyzeCommentSentiment(commentText) {
  await delay(500);

  return {
    sentiment: "Positive",
    emotion: "Happy",
    toxic: false,
    score: 0.8,
    flag: "none"
  };
}

// ──────────────────────────────────────────────
// 5. RECOMMENDATIONS
// ──────────────────────────────────────────────
export async function getRecommendations(readHistory, allPosts) {
  await delay(600);

  return allPosts.slice(0, 3);
}
